// Combine multiple city endpoints; allows JSON or HTML feed URLs.
const urls = [
  $json['CITY_1_PERMITS_URL'],
  $json['CITY_2_PERMITS_URL']
].filter(Boolean);
return urls.map(u => ({json: {url: u}}));

/**
 * Attempts to parse either JSON (CKAN/Socrata style) or HTML tables into a normalized list of permits.
 * For HTML, looks for rows with columns like Address, Description, IssueDate.
 */
const input = items[0].json;
const body = input.body || input; // http node returns body in .json.body (string)
let permits = [];
try {
  const data = typeof body === 'string' ? JSON.parse(body) : body;
  // Try common Socrata format
  if (Array.isArray(data)) {
    // Assume array of permit objects
    permits = data;
  } else if (data && data.data && Array.isArray(data.data)) {
    permits = data.data;
  }
} catch(e){
  // Fallback: naive HTML parse via regex (works for simple <tr><td>)
  const html = String(body);
  const rows = html.split(/<tr[^>]*>/i).slice(1);
  for (const r of rows) {
    const tds = r.split(/<td[^>]*>/i).slice(1).map(x => x.replace(/<[^>]+>/g,'').trim());
    if (tds.length >= 3) {
      permits.push({
        address: tds[0],
        description: tds[1],
        issued: tds[2],
      });
    }
  }
}

return permits.map(p => ({json: {raw: p}}));

/**
 * Normalize fields to: address, project, issued_at, city, contact_url
 */
function pick(obj, keys){
  const out={};
  for (const k of keys){
    if (obj[k]!==undefined) out[k]=obj[k];
  }
  return out;
}
const tradeRegex = new RegExp($item(0).$node["Config Vars"].json["TRADE_KEYWORDS"], 'i');
const city = $item(0).$node["Config Vars"].json["MARKET_NAME"];
const normalized = [];

for (const item of items){
  const r = item.json.raw;
  const rec = {
    address: r.address || r.Address || r.site_address || r.location || r['Site Address'] || '',
    project: r.description || r.Description || r.work_description || r['Work Description'] || '',
    issued_at: r.issued || r.issue_date || r['Issue Date'] || r.permit_issued_date || '',
    permit_no: r.permit || r.permit_number || r['Permit Number'] || '',
    city
  };
  // Filter to trades of interest
  if ((rec.project||'').match(tradeRegex)){
    normalized.push({json: rec});
  }
}
return normalized;

// De-dupe by (permit_no || address+project+issued_at) using a simple in-memory cache
// For production, use Redis node or a Database node.
const seen = (global.get('seenPermits') || new Set());
const out = [];
for (const item of items){
  const j = item.json;
  const key = (j.permit_no || (j.address+'|'+j.project+'|'+j.issued_at)).toLowerCase();
  if (!seen.has(key)){
    seen.add(key);
    out.push(item);
  }
}
global.set('seenPermits', seen);
return out;

// Prepare a teaser list (first N) for outbound email/DM.
const N = parseInt($item(0).$node["Config Vars"].json["SAMPLE_LEADS_TO_SEND"]) || 3;
return items.slice(0, N);

